// dispatch(name, x): find the registered handler whose name === name and call
// its handle(x). Throws if no handler matches.
const { all } = require("./index.js");
function dispatch(name, x) {
  const h = all().find((handler) => handler.name === name);
  if (!h) {
    throw new Error(`unknown handler: ${name}`);
  }
  return h.handle(x);
}
module.exports = { dispatch };
